import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: unknown;
}

function useComponent(props: Props) {
  const data = useMemo(() => {
    return props.properties as any;
  }, [props.properties]);

  const getWeatherEmoji = useCallback((condition: string) => {
    const c = condition?.toLowerCase() || '';
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('fog') || c.includes('mist')) return '🌫️';
    return '🌡️';
  }, []);

  const isValid = useMemo(() => {
    return data && typeof data === 'object' && data.location && data.current;
  }, [data]);

  return { data, getWeatherEmoji, isValid };
}

export default function Component(props: Props) {
  const { data, getWeatherEmoji, isValid } = useComponent(props);

  if (!isValid) {
    return (
      <Container maxWidth="sm" padding={16}>
        <Alert variant="info" title="Weather Data Required">
          Please provide weather properties including location, current conditions, and forecast.
        </Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="sm" padding={16}>
      <Card padding={24} shadow="lg" radius="xl" border={true}>
        <Stack gap={24}>
          {/* Location and Date */}
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {data.location}
            </Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
            </Text>
          </Stack>

          {/* Hero Temperature Section */}
          <Stack direction="horizontal" align="center" justify="between">
            <Stack gap={0}>
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
                {data.current.temp}°
              </Text>
              <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {data.current.condition}
              </Text>
            </Stack>
            <Box style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}>
              {getWeatherEmoji(data.current.condition)}
            </Box>
          </Stack>

          {/* Environmental Details */}
          <Stack direction="horizontal" gap={24}>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              💧 Humidity: {data.current.humidity}%
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              💨 Wind: {data.current.windSpeed} mph
            </Text>
          </Stack>

          <Divider margin={8} />

          {/* 5-Day Forecast */}
          <Stack direction="horizontal" justify="between" gap={4}>
            {data.forecast?.slice(0, 5).map((day: any, i: number) => (
              <Stack key={i} align="center" gap={8} style={{ flex: 1 }}>
                <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {day.day}
                </Text>
                <Box style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }}>
                  {getWeatherEmoji(day.condition)}
                </Box>
                <Stack gap={0} align="center">
                  <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    {day.high}°
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" size="xs">
                    {day.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: unknown;
}

// Action handlers (call these from event handlers):
//   props.actions: {"submit":{"label":"Submit Survey","description":"Called with all collected answers as a structured object","example":{"name":"John","email":"john@example.com","satisfaction":4,"features":["API Integration","Mobile App"],"comments":"Great product!"}}}
function useComponent(props: Props) {
  const properties = (props.properties as any) || {};
  const actions = (props as any).actions || {};

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: ''
  });

  const satisfactionOptions = useMemo(() => {
    const labels = properties.satisfactionLabels || ['Very Dissatisfied', 'Dissatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'];
    return labels.slice(0, 5).map((label: string, index: number) => ({
      value: String(index + 1),
      label: label,
    }));
  }, [properties.satisfactionLabels]);

  const featureOptions = useMemo(() => properties.featureOptions || ['Offline Support', 'Mobile App', 'Dark Mode', 'Advanced Search', 'Export Data'], [properties.featureOptions]);

  const isEmailValid = useCallback((email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email), []);

  const validation = useMemo(() => ({
    name: formData.name.trim().length > 0,
    email: isEmailValid(formData.email),
    satisfaction: formData.satisfaction !== ''
  }), [formData, isEmailValid]);

  const isStepValid = useMemo(() => {
    if (step === 1) return validation.name && validation.email;
    if (step === 2) return validation.satisfaction;
    return true; // Step 3, 4, 5 are always "valid" (optional)
  }, [step, validation]);

  const nextStep = useCallback(() => {
    if (isStepValid) setStep(s => Math.min(s + 1, 5));
  }, [isStepValid]);

  const prevStep = useCallback(() => setStep(s => Math.max(s - 1, 1)), []);

  const updateField = useCallback((field: string, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  const toggleFeature = useCallback((feature: string) => {
    setFormData(prev => {
      const features = prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature];
      return { ...prev, features };
    });
  }, []);

  const handleSubmit = useCallback(() => {
    if (actions.submit) {
      actions.submit({
        ...formData,
        satisfaction: formData.satisfaction ? Number(formData.satisfaction) : undefined
      });
    }
  }, [actions, formData]);

  return {
    step,
    formData,
    satisfactionOptions,
    featureOptions,
    isStepValid,
    validation,
    nextStep,
    prevStep,
    updateField,
    toggleFeature,
    handleSubmit
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap={24}>
        {/* Header & Progress */}
        <Stack gap={8}>
          <Heading level={2}>Survey Feedback</Heading>
          <Stack direction="horizontal" justify="between" align="center">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {state.step === 5 ? 'Step 5: Review' : `Step ${state.step} of 4`}
            </Text>
            <Text variant="caption" weight="medium" color="var(--ggui-color-primary-600, #0284c7)">
              {Math.round((state.step / 5) * 100)}% Complete
            </Text>
          </Stack>
          <Progress value={state.step} max={5} size="md" />
        </Stack>

        {/* Main Content Card */}
        <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="xl">
          <Box paddingY={8}>
            {state.step === 1 && (
              <Stack gap={20}>
                <Heading level={4}>Personal Information</Heading>
                <Input label="Full Name"
                  required
                  placeholder="Enter your name"
                  value={state.formData.name}
                  onChange={(val) => state.updateField('name', val)}
                  error={state.formData.name !== '' && !state.validation.name ? 'Please enter your name' : undefined}
                />
                <Input label="Email Address"
                  required
                  type="email"
                  placeholder="you@example.com"
                  value={state.formData.email}
                  onChange={(val) => state.updateField('email', val)}
                />
              </Stack>
            )}

            {state.step === 2 && (
              <Stack gap={20}>
                <Heading level={4}>Satisfaction Rating</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  How satisfied are you with our service?
                </Text>
                <RadioGroup
                  label="Select a rating"
                  options={state.satisfactionOptions}
                  value={state.formData.satisfaction}
                  onChange={(val) => state.updateField('satisfaction', val)}
                  direction="vertical"
                />
              </Stack>
            )}

            {state.step === 3 && (
              <Stack gap={20}>
                <Heading level={4}>Feature Interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Which features are you most interested in? (Select all that apply)
                </Text>
                <Stack gap={12}>
                  {state.featureOptions.map((feature: string) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={state.formData.features.includes(feature)}
                      onChange={() => state.toggleFeature(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {state.step === 4 && (
              <Stack gap={20}>
                <Heading level={4}>Additional Comments</Heading>
                <TextArea
                  label="Your Feedback"
                  placeholder="Tell us more about your experience..."
                  value={state.formData.comments}
                  onChange={(val) => state.updateField('comments', val)}
                  rows={6}
                  maxLength={500}
                  showCount
                  helperText="Optional: Your feedback helps us improve."
                />
              </Stack>
            )}

            {state.step === 5 && (
              <Stack gap={20}>
                <Heading level={4}>Review Your Answers</Heading>
                <Stack gap={16}>
                  <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12}>
                    <Stack gap={12}>
                      <Stack gap={2}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name & Email</Text>
                        <Text weight="medium">{state.formData.name} • {state.formData.email}</Text>
                      </Stack>
                      <Divider margin={4} />
                      <Stack gap={2}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                        <Text weight="medium">
                          {state.satisfactionOptions.find(o => o.value === state.formData.satisfaction)?.label || 'Not rated'}
                        </Text>
                      </Stack>
                      <Divider margin={4} />
                      <Stack gap={2}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Interests</Text>
                        <Text weight="medium">
                          {state.formData.features.length > 0 ? state.formData.features.join(', ') : 'No interests selected'}
                        </Text>
                      </Stack>
                      {state.formData.comments && (
                        <>
                          <Divider margin={4} />
                          <Stack gap={2}>
                            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                            <Text weight="medium">{state.formData.comments}</Text>
                          </Stack>
                        </>
                      )}
                    </Stack>
                  </Box>
                  <Alert variant="info" title="Final Step">
                    Please review your information before submitting.
                  </Alert>
                </Stack>
              </Stack>
            )}
          </Box>
        </Card>

        {/* Footer Navigation */}
        <Stack direction="horizontal" justify="between" align="center">
          <Button
            variant="ghost"
            onClick={state.prevStep}
            disabled={state.step === 1}
            leftIcon={<Icon name="chevron-left" size={16} />}
          >
            Back
          </Button>

          <Stack direction="horizontal" gap={12}>
            {state.step < 5 ? (
              <Button
                variant="primary"
                onClick={state.nextStep}
                disabled={!state.isStepValid}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={state.handleSubmit}
                leftIcon={<Icon name="check" size={16} />}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo, useCallback } from 'react';
import { Container, Card, Stack, Box, Divider, Text, Heading, Button, Input, Select, Badge, Icon, Avatar, Progress } from '@ggui-ai/design/primitives';

interface Props {
  properties?: {
    tasks?: Task[];
  };
  actions?: {
    taskUpdate?: (payload: { action: string; taskId: string; data: any }) => void;
  };
}

export interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: { name: string; avatar?: string };
  dueDate?: string;
  column: 'todo' | 'in-progress' | 'done';
}

const COLUMNS = [
  { id: 'todo', label: 'To Do' },
  { id: 'in-progress', label: 'In Progress' },
  { id: 'done', label: 'Done' },
] as const;

// Action handlers (call these from event handlers):
//   props.actions: {"taskUpdate":{"label":"Task Updated","description":"Called when a task is moved, edited, or created. Payload: { action, taskId, data }","example":{"action":"move","taskId":"1","data":{"column":"in-progress"}}}}
function useComponent(props: Props) {
  const initialTasks: Task[] = props.properties?.tasks || [
    { id: '1', title: 'Research competitors', priority: 'high', assignee: { name: 'Alice' }, column: 'todo' },
    { id: '2', title: 'Draft technical specifications', priority: 'medium', assignee: { name: 'Bob' }, column: 'todo' },
    { id: '3', title: 'Initialize project repository', priority: 'low', assignee: { name: 'Charlie' }, column: 'in-progress' },
    { id: '4', title: 'Define project scope', priority: 'high', assignee: { name: 'Alice' }, column: 'done' },
  ];

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const onTaskUpdate = useCallback((action: string, taskId: string, data: any) => {
    props.actions?.taskUpdate?.({ action, taskId, data });
  }, [props.actions]);

  const moveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn as any } : t));
    onTaskUpdate('move', taskId, { column: newColumn });
  }, [onTaskUpdate]);

  const addNewTask = useCallback((column: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask: Task = {
      id: Math.random().toString(36).substring(2, 11),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: { name: 'Me' },
      column: column as any,
    };
    setTasks(prev => [...prev, newTask]);
    onTaskUpdate('create', newTask.id, newTask);
    setNewTaskTitle('');
    setAddingToColumn(null);
  }, [newTaskTitle, newTaskPriority, onTaskUpdate]);

  const startEditing = useCallback((task: Task) => {
    setEditingTaskId(task.id);
    setEditValue(task.title);
  }, []);

  const saveEdit = useCallback((taskId: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: editValue } : t));
    onTaskUpdate('edit', taskId, { title: editValue });
    setEditingTaskId(null);
  }, [editValue, onTaskUpdate]);

  const stats = useMemo(() => ({
    total: tasks.length,
    completed: tasks.filter(t => t.column === 'done').length,
  }), [tasks]);

  return {
    tasks,
    moveTask,
    addNewTask,
    startEditing,
    saveEdit,
    editValue,
    setEditValue,
    editingTaskId,
    setEditingTaskId,
    stats,
    addingToColumn,
    setAddingToColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius={12} style={{ border: '1px solid var(--ggui-color-outlineVariant)' }}>
          <Stack direction="horizontal" justify="between" align="center" gap={24}>
            <Stack direction="horizontal" align="center" gap={12}>
              <Box background="var(--ggui-color-primary-600)" borderRadius={8} padding={8}>
                <Icon name="check" color="var(--ggui-color-surface, #ffffff)" size={20} />
              </Box>
              <Stack gap={0}>
                <Heading level={3}>Project Kanban</Heading>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Task Management Dashboard</Text>
              </Stack>
            </Stack>

            <Stack direction="horizontal" align="center" gap={32} style={{ flex: 1, maxWidth: '600px' }}>
              <Stack direction="vertical" gap={4} style={{ flex: 1 }}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="overline">COMPLETION RATE</Text>
                  <Text variant="label" size="xs" color="var(--ggui-color-primary-600)">
                    {state.stats.total > 0 ? Math.round((state.stats.completed / state.stats.total) * 100) : 0}%
                  </Text>
                </Stack>
                <Progress value={state.stats.total > 0 ? (state.stats.completed / state.stats.total) * 100 : 0} variant="default" size="sm" />
              </Stack>

              <Stack direction="horizontal" gap={16}>
                <Box padding="4px 12px" borderRadius="var(--ggui-shape-radius-sm)" background="var(--ggui-color-surface)">
                  <Stack direction="horizontal" align="center" gap={8}>
                    <Text variant="label" size="sm">Total:</Text>
                    <Text weight="bold" size="lg">{state.stats.total}</Text>
                  </Stack>
                </Box>
                <Box padding="4px 12px" borderRadius="var(--ggui-shape-radius-sm)" background="var(--ggui-color-success-50)">
                  <Stack direction="horizontal" align="center" gap={8}>
                    <Text variant="label" size="sm" color="var(--ggui-color-success-700)">Done:</Text>
                    <Text weight="bold" size="lg" color="var(--ggui-color-success-700)">{state.stats.completed}</Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Stack>
        </Box>

        {/* Board Columns */}
        <Stack direction="horizontal" gap={20} align="start" style={{ overflowX: 'auto', paddingBottom: '12px' }}>
          {COLUMNS.map(col => {
            const columnTasks = state.tasks.filter(t => t.column === col.id);
            return (
              <Stack key={col.id} gap={16} style={{ flex: 1, minWidth: '320px', background: 'var(--ggui-color-surfaceVariant)', padding: '16px', borderRadius: '12px', border: '1px solid var(--ggui-color-outlineVariant)' }}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Stack direction="horizontal" align="center" gap={8}>
                    <Heading level={4}>{col.label}</Heading>
                    <Badge variant={col.id === 'done' ? 'success' : 'primary'}>{columnTasks.length}</Badge>
                  </Stack>
                  <Button variant="ghost" size="xs"><Icon name="menu" size={14} /></Button>
                </Stack>

                <Stack gap={12}>
                  {columnTasks.map(task => (
                    <Card key={task.id} padding={16} shadow="sm" radius="md">
                      <Stack gap={12}>
                        <Stack direction="horizontal" justify="between" align="start">
                          <Box style={{ flex: 1 }}>
                            {state.editingTaskId === task.id ? (
                              <Stack direction="horizontal" gap={8} align="end">
                                <Input label="Rename Task"
                                  value={state.editValue}
                                  onChange={state.setEditValue}
                                  autoFocus
                                  size="sm"
                                />
                                <Button size="xs" onClick={() => state.saveEdit(task.id)}><Icon name="check" size={12} /></Button>
                              </Stack>
                            ) : (
                              <Box style={{ cursor: 'pointer' }}>
                                <Text weight="medium">
                                  {task.title}
                                </Text>
                              </Box>
                            )}
                          </Box>
                          <Button variant="ghost" size="xs" onClick={() => state.startEditing(task)}>
                            <Icon name="settings" size={14} />
                          </Button>
                        </Stack>

                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant={
                            task.priority === 'high' ? 'error' : 
                            task.priority === 'medium' ? 'warning' : 'info'
                          } size="sm">
                            {task.priority.toUpperCase()}
                          </Badge>
                          <Avatar name={task.assignee.name} src={task.assignee.avatar} size="xs" />
                        </Stack>

                        <Divider margin={4} />

                        <Stack direction="horizontal" align="center" gap={8}>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ flexShrink: 0 }}>MOVE:</Text>
                          <Select
                            label="Move to"
                            size="sm"
                            value={task.column}
                            onChange={(val) => state.moveTask(task.id, val)}
                            options={COLUMNS.filter(c => c.id !== task.column).map(c => ({ value: c.id, label: c.label }))}
                            placeholder="Move to..."
                          />
                        </Stack>
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {state.addingToColumn === col.id ? (
                  <Box padding={16} borderRadius="var(--ggui-shape-radius-md)" background="var(--ggui-color-surface)" style={{ border: '1px solid var(--ggui-color-outline)' }}>
                    <Stack gap={16}>
                      <Input label="New Task Title"
                        placeholder="Task name..."
                        value={state.newTaskTitle}
                        onChange={state.setNewTaskTitle}
                        autoFocus
                        required
                      />
                      <Select
                        label="Priority"
                        value={state.newTaskPriority}
                        onChange={(v) => state.setNewTaskPriority(v as any)}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Stack direction="horizontal" gap={8} justify="end">
                        <Button variant="ghost" size="sm" onClick={() => state.setAddingToColumn(null)}>Cancel</Button>
                        <Button size="sm" onClick={() => state.addNewTask(col.id)} disabled={!state.newTaskTitle.trim()}>Add Task</Button>
                      </Stack>
                    </Stack>
                  </Box>
                ) : (
                  <Button variant="outline" fullWidth onClick={() => {
                    state.setAddingToColumn(col.id);
                    state.setNewTaskTitle('');
                    state.setNewTaskPriority('medium');
                  }}>
                    <Icon name="plus" size={16} /> Add Task
                  </Button>
                )}
              </Stack>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion, MotionKeyframes } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: {
    elements?: ElementData[];
  };
}

interface ElementData {
  name: string;
  appearance: string;
  atomic_mass: number;
  category: string;
  number: number;
  period: number;
  symbol: string;
  xpos: number;
  ypos: number;
  summary: string;
  phase: string;
  melt?: number;
  boil?: number;
  density?: number;
  discovered_by?: string;
}

const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-success-500, #22c55e)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  'metalloid': 'var(--ggui-color-info-700, #0e7490)',
  'diatomic nonmetal': 'var(--ggui-color-primary-400, #38bdf8)',
  'polyatomic nonmetal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'noble gas': 'var(--ggui-color-primary-800, #075985)',
  'lanthanide': 'var(--ggui-color-primary-200, #bae6fd)',
  'actinide': 'var(--ggui-color-primary-300, #7dd3fc)',
};

const getCategoryColor = (category: string) => {
  const key = category.toLowerCase();
  return CATEGORY_COLORS[key] || 'var(--ggui-color-outline, #d4d4d8)';
};

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedNumber, setSelectedNumber] = useState<number | null>(null);

  const elements = props.properties?.elements || [];

  const filteredElements = useMemo(() => {
    if (!searchQuery) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(el => 
      el.name.toLowerCase().includes(query) || 
      el.symbol.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  const selectedElement = useMemo(() => 
    elements.find(el => el.number === selectedNumber) || null
  , [elements, selectedNumber]);

  const categories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach(el => cats.add(el.category));
    return Array.from(cats).sort();
  }, [elements]);

  return {
    searchQuery,
    setSearchQuery,
    selectedNumber,
    setSelectedNumber,
    filteredElements,
    selectedElement,
    categories,
    elements,
  };
}

