interface Props {
  properties: unknown;
}

// Action handlers (call these from event handlers):
//   props.actions: {"addToCart":{"label":"Add to Cart","description":"Called when user clicks Add to Cart. Payload: { productId, quantity }","example":{"productId":"prod-001","quantity":2}}}
function useComponent(props: Props) {
  const properties = (props.properties as any) || {};
  const product = useMemo(() => ({
    productId: properties.productId || 'unknown',
    name: properties.name || 'Product Name',
    price: properties.price || 0,
    currency: properties.currency || '$',
    description: properties.description || '',
    stock: properties.stock ?? 0,
    rating: properties.rating || 0,
    specifications: properties.specifications || [],
    reviews: properties.reviews || [],
    imageUrl: properties.imageUrl,
  }), [properties]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const handleQuantityChange = useCallback((val: number) => {
    const next = Math.max(1, Math.min(val, product.stock));
    setQuantity(next);
  }, [product.stock]);

  const handleAddToCart = useCallback(() => {
    if (product.stock > 0 && (props as any).actions?.addToCart) {
      (props as any).actions.addToCart({
        productId: product.productId,
        quantity: quantity,
      });
    }
  }, [product.productId, product.stock, quantity, props]);

  const stockStatus = useMemo(() => {
    if (product.stock <= 0) return { label: 'Out of Stock', variant: 'error' as const };
    if (product.stock < 10) return { label: 'Low Stock', variant: 'warning' as const };
    return { label: 'In Stock', variant: 'success' as const };
  }, [product.stock]);

  const specColumns = [
    { key: 'key', header: 'Specification', width: '40%' },
    { key: 'value', header: 'Detail' },
  ];

  return {
    product,
    quantity,
    activeTab,
    stockStatus,
    specColumns,
    handleQuantityChange,
    handleAddToCart,
    setActiveTab,
  };
}

