import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: unknown;
  actions?: {
    sendMessage?: (payload: { text: string; timestamp: string }) => void;
  };
}

// Action handlers (call these from event handlers):
//   props.actions: {"sendMessage":{"label":"Send Message","description":"Called when user sends a message. Payload: { text, timestamp }","example":{"text":"Sounds good!","timestamp":"2026-03-15T14:10:00Z"}}}
function useComponent(props: Props) {
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const properties = props.properties as {
    title?: string;
    participantsCount?: number;
    messages?: Array<{
      id: string;
      text: string;
      timestamp: string;
      sender: { id: string; name: string; avatar?: string };
    }>;
    currentUser?: { id: string; name: string };
  };

  const data = useMemo(() => ({
    title: properties?.title || 'Chat',
    participantsCount: properties?.participantsCount || 0,
    messages: properties?.messages || [],
    currentUser: properties?.currentUser || { id: 'current-user', name: 'You' }
  }), [properties]);

  const scrollToBottom = useCallback((behavior: ScrollBehavior = 'smooth') => {
    messagesEndRef.current?.scrollIntoView({ behavior });
  }, []);

  useEffect(() => {
    scrollToBottom('auto');
  }, [scrollToBottom]);

  useEffect(() => {
    if (data.messages.length > 0) {
      scrollToBottom('smooth');
    }
  }, [data.messages.length, scrollToBottom]);

  const handleSend = useCallback(() => {
    if (!inputValue.trim()) return;

    if (props.actions?.sendMessage) {
      props.actions.sendMessage({
        text: inputValue,
        timestamp: new Date().toISOString(),
      });
    }
    setInputValue('');
  }, [inputValue, props.actions]);

  const formatTime = (timestamp: string) => {
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch (e) {
      return '';
    }
  };

  return {
    inputValue,
    setInputValue,
    handleSend,
    messagesEndRef,
    data,
    formatTime
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const { data, inputValue, setInputValue, handleSend, messagesEndRef, formatTime } = state;

  return (
    <Container maxWidth="md" padding={16}>
      <Card padding={0} shadow="md" border radius="xl" style={{ display: 'flex', flexDirection: 'column', height: '600px', overflow: 'hidden' }}>
