                      padding="8px 12px" 
                      radius="lg" 
                      shadow="none"
                      border={!isMe}
                      style={{ 
                        backgroundColor: isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        color: isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)',
                        maxWidth: '80%',
                        borderRadius: isMe 
                          ? (isFirstInGroup ? '12px 12px 4px 12px' : '12px 4px 4px 12px')
                          : (isFirstInGroup ? '12px 12px 12px 4px' : '4px 12px 12px 4px')
                      }}
                    >
                      <Text style={{ color: 'inherit' }}>{msg.text}</Text>
                    </Card>
                  </Stack>

                  {index === data.messages.length - 1 && (
                    <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ marginTop: 4, marginLeft: isMe ? 4 : 40, marginRight: isMe ? 40 : 4 }}>
                      {formatTime(msg.timestamp)}
                    </Text>
                  )}
                </Box>
              );
            })}
            <div ref={messagesEndRef} />
          </Stack>
        </Box>

        {/* Input Area */}
        <Box 
          padding={16} 
          background="var(--ggui-color-surface, #ffffff)" 
          style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', flexShrink: 0 }}
        >
          <Stack direction="horizontal" gap={12} align="center">
            <Box style={{ flex: 1 }}>
              <Input label="Message" value={inputValue} onChange={setInputValue} placeholder="Type a message..." onKeyDown={(e: any) => e.key === 'Enter' && handleSend()} />
            </Box>
            <Button 
              variant="primary" 
              onClick={handleSend} 
              disabled={!inputValue.trim()}
              rightIcon={<Icon name="check" size={16} />}
            >
              Send
            </Button>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
