import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: unknown;
}

// Action handlers (call these from event handlers):
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}
function useComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState(() => {
    const initial = (props.properties as any) || {};
    return {
      name: initial.name || '',
      email: initial.email || '',
      avatar: initial.avatar || '🧑‍💻',
      role: initial.role || 'Developer',
      emailNotifications: initial.emailNotifications !== undefined ? initial.emailNotifications : true,
      theme: initial.theme || 'light'
    };
  });

  const isEmailValid = useMemo(() => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
  }, [formData.email]);

  const canGoNext = useMemo(() => {
    if (currentStep === 1) {
      return formData.name.trim().length > 0 && isEmailValid;
    }
    return true;
  }, [currentStep, formData, isEmailValid]);

  const handleNext = useCallback(() => {
    if (canGoNext) setCurrentStep(s => Math.min(3, s + 1));
  }, [canGoNext]);

  const handleBack = useCallback(() => {
    setCurrentStep(s => Math.max(1, s - 1));
  }, []);

  const handleComplete = useCallback(() => {
    const actions = (props as any).actions;
    if (actions?.complete) {
      actions.complete(formData);
    }
  }, [formData, props]);

  const updateField = useCallback((field: string, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  return {
    currentStep,
    formData,
    updateField,
    canGoNext,
    handleNext,
    handleBack,
    handleComplete,
    isEmailValid
  };
}

