import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  title: string;
  features: string[];
  onSubmit: (data: any) => void;
}

function useComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '3',
    features: [] as string[],
    comments: ''
  });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isCurrentStepValid = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    return true;
  }, [step, formData]);

  const next = () => setStep((s) => Math.min(s + 1, 5));
  const back = () => setStep((s) => Math.max(s - 1, 1));
  const update = (key: string, value: any) => setFormData((d) => ({ ...d, [key]: value }));

  const submit = () => props.onSubmit(formData);

  return { step, formData, update, next, back, submit, isCurrentStepValid };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>{props.title}</Heading>
        <Progress value={(state.step - 1) * 25} max={100} />
        <Text variant="label">Step {state.step} of 4</Text>

        <Card padding={24}>
          {state.step === 1 && (
            <Stack gap={16}>
              <Input label="Name" value={state.formData.name} onChange={(v) => state.update('name', v)} required />
              <Input label="Email" value={state.formData.email} onChange={(v) => state.update('email', v)} required />
            </Stack>
          )}
          {state.step === 2 && (
            <RadioGroup label="Satisfaction Rating" value={state.formData.satisfaction} onChange={(v) => state.update('satisfaction', v)} options={[
              { value: '1', label: '1 - Poor' }, { value: '2', label: '2' }, { value: '3', label: '3 - Neutral' }, { value: '4', label: '4' }, { value: '5', label: '5 - Excellent' }
            ]} />
          )}
          {state.step === 3 && (
            <Stack gap={8}>
              <Text variant="label">Feature Interests</Text>
              {props.features.map(f => (
                <Checkbox key={f} label={f} checked={state.formData.features.includes(f)} onChange={(checked) => {
                  const fts = checked ? [...state.formData.features, f] : state.formData.features.filter(x => x !== f);
                  state.update('features', fts);
                }} />
              ))}
            </Stack>
          )}
          {state.step === 4 && (
            <TextArea label="Comments" value={state.formData.comments} onChange={(v) => state.update('comments', v)} maxLength={500} showCount />
          )}
        </Card>

        <Stack direction="horizontal" justify="between">
          <Button variant="ghost" onClick={state.back} disabled={state.step === 1}>Back</Button>
          {state.step < 4 ? (
            <Button variant="primary" onClick={state.next} disabled={!state.isCurrentStepValid}>Next</Button>
          ) : (
            <Button variant="primary" onClick={state.submit}>Submit Survey</Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Button, Input, Select, Badge, Avatar, Spacer } from '@ggui-ai/design/primitives';

interface Props {
  tasks: Array<{ id: string; title: string; column: 'todo' | 'in-progress' | 'done'; priority: 'low' | 'medium' | 'high'; assignee: string; dueDate?: string }>;
  onTaskUpdate: (payload: { action: string; taskId: string; data: any }) => void;
}

function useComponent(props: Props) {
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');

  const columns = useMemo(() => [
    { id: 'todo', label: 'To Do' },
    { id: 'in-progress', label: 'In Progress' },
    { id: 'done', label: 'Done' },
  ], []);

  const addTask = useCallback((column: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      column: column as any,
      priority: 'medium',
      assignee: 'Unassigned',
    };
    setTasks(prev => [...prev, newTask]);
    props.onTaskUpdate({ action: 'create', taskId: newTask.id, data: newTask });
    setNewTaskTitle('');
    setAddingTo(null);
  }, [newTaskTitle, props]);

  const moveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn as any } : t));
    props.onTaskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [props]);

  return { tasks, columns, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, addTask, moveTask };
}

export default function Component(props: Props) {
  const { tasks, columns, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, addTask, moveTask } = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Project Board</Heading>
        <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius="md">
          <Text>Total Tasks: {tasks.length} | Completed: {tasks.filter(t => t.column === 'done').length}</Text>
        </Box>
        <Box style={{ display: 'flex', gap: 'var(--ggui-spacing-4, 16px)', alignItems: 'flex-start' }}>
          {columns.map(col => (
            <Stack key={col.id} gap={8} style={{ flex: 1 }}>
              <Heading level={4}>{col.label} ({tasks.filter(t => t.column === col.id).length})</Heading>
              {tasks.filter(t => t.column === col.id).map(task => (
                <Card key={task.id} padding={12} shadow="sm">
                  <Stack gap={8}>
                    <Text>{task.title}</Text>
                    <Box style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'default'}>{task.priority}</Badge>
                      <Select
                        value={task.column}
                        onChange={(val) => moveTask(task.id, val)}
                        options={[
                          { value: 'todo', label: 'To Do' },
                          { value: 'in-progress', label: 'In Progress' },
                          { value: 'done', label: 'Done' }
                        ]}
                      />
                    </Box>
                  </Stack>
                </Card>
              ))}
              {addingTo === col.id ? (
                <Box>
                  <Input label="New Task" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Task title..." />
                  <Stack direction="horizontal" gap={8} style={{ marginTop: 8 }}>
                    <Button size="sm" onClick={() => addTask(col.id)}>Add</Button>
                    <Button size="sm" variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
                  </Stack>
                </Box>
              ) : (
                <Button variant="ghost" onClick={() => setAddingTo(col.id)}>+ Add Task</Button>
              )}
            </Stack>
          ))}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Input } from '@ggui-ai/design/primitives';

interface ElementData {
  name: string;
  symbol: string;
  atomicNumber: number;
  atomicWeight: number;
  category: string;
  x: number;
  y: number;
}

interface Props {
  elements: ElementData[];
}

function useComponent(props: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    const lower = searchTerm.toLowerCase();
    return props.elements.filter(
      (el) => el.name.toLowerCase().includes(lower) || el.symbol.toLowerCase().includes(lower)
    );
  }, [props.elements, searchTerm]);

  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'noble-gas': return 'var(--ggui-color-info-200, #cffafe)';
      case 'halogen': return 'var(--ggui-color-warning-200, #fde68a)';
      case 'alkali-metal': return 'var(--ggui-color-error-200, #fecaca)';
      default: return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
    }
  };

  return { searchTerm, setSearchTerm, selectedElement, setSelectedElement, filteredElements, getCategoryColor };
}

export default function Component(props: Props) {
  const { searchTerm, setSearchTerm, selectedElement, setSelectedElement, filteredElements, getCategoryColor } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>
        <Input 
          label="Search Elements" 
          value={searchTerm} 
          onChange={setSearchTerm} 
          placeholder="Search by name or symbol..." 
        />

        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, 1fr)', 
          gap: 'var(--ggui-spacing-1, 4px)',
          backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          padding: 'var(--ggui-spacing-2, 8px)',
          borderRadius: 'var(--ggui-shape-radius-md, 8px)'
        }}>
          {props.elements.map((el) => {
            const isVisible = filteredElements.includes(el);
            return (
              <div
                key={el.atomicNumber}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridColumn: `${el.x}`,
                  gridRow: `${el.y}`,
                  padding: 'var(--ggui-spacing-1, 4px)',
                  cursor: 'pointer',
                  backgroundColor: getCategoryColor(el.category),
                  opacity: isVisible ? 1 : 0.2
                }}
              >
                <Card padding={4} radius="sm">
                  <Text size="xs">{el.atomicNumber}</Text>
                  <Heading level={4}>{el.symbol}</Heading>
                </Card>
              </div>
            );
          })}
        </Box>

        {selectedElement && (
          <Card padding={24}>
            <Stack gap={8}>
              <Heading level={3}>{selectedElement.name} ({selectedElement.symbol})</Heading>
              <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text>Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text>Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

