import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  product: {
    id: string;
    name: string;
    price: number;
    currency: string;
    rating: number;
    stock: number;
    description: string;
    specifications: { key: string; value: string }[];
    reviews: { author: string; rating: number; text: string; date: string }[];
  };
  actions: {
    addToCart: (payload: { productId: string; quantity: number }) => void;
  };
}

function useComponent(props: Props) {
  const [quantity, setQuantity] = useState(1);

  const increment = useCallback(() => setQuantity(q => Math.min(props.product.stock, q + 1)), [props.product.stock]);
  const decrement = useCallback(() => setQuantity(q => Math.max(1, q - 1)), []);

  const handleAddToCart = useCallback(() => {
    props.actions.addToCart({ productId: props.product.id, quantity });
  }, [props.product.id, quantity, props.actions]);

  const stockStatus = useMemo(() => {
    if (props.product.stock === 0) return { label: 'Out of Stock', variant: 'error' as const };
    if (props.product.stock < 5) return { label: 'Low Stock', variant: 'warning' as const };
    return { label: 'In Stock', variant: 'success' as const };
  }, [props.product.stock]);

  return { quantity, increment, decrement, handleAddToCart, stockStatus };
}

export default function Component(props: Props) {
  const { product } = props;
  const { quantity, increment, decrement, handleAddToCart, stockStatus } = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack direction="horizontal" gap={32} wrap>
        <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={16} padding={48} style={{ flex: 1, minWidth: 300 }}>
          <Heading level={2} align="center">{product.name}</Heading>
        </Box>
        <Stack gap={16} style={{ flex: 1, minWidth: 300 }}>
          <Heading level={1}>{product.name}</Heading>
          <Text variant="bodyLarge" weight="semibold">{product.currency}{product.price.toFixed(2)}</Text>
          <Text>Rating: {'★'.repeat(Math.round(product.rating))}{'☆'.repeat(5 - Math.round(product.rating))}</Text>
          <Badge variant={stockStatus.variant}>{stockStatus.label}</Badge>

          <Stack direction="horizontal" gap={16} align="center">
            <Button variant="outline" size="sm" onClick={decrement}>-</Button>
            <Text>{quantity}</Text>
            <Button variant="outline" size="sm" onClick={increment}>+</Button>
            <Button variant="primary" disabled={product.stock === 0} onClick={handleAddToCart}>Add to Cart</Button>
          </Stack>
        </Stack>
      </Stack>

      <Spacer size={32} />

      <Tabs items={[
        { key: 'desc', label: 'Description', content: <Text>{product.description}</Text> },
        { key: 'specs', label: 'Specifications', content: <Table columns={[{key: 'key', header: 'Key'}, {key: 'value', header: 'Value'}]} data={product.specifications} /> },
        { key: 'reviews', label: 'Reviews', content: <Stack gap={16}>{product.reviews.map((r, i) => <Card key={i}><Text weight="bold">{r.author} ({r.rating}/5)</Text><Text>{r.text}</Text></Card>)}</Stack> }
      ]} />
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  title: string;
  messages: { id: string; sender: string; text: string; timestamp: string }[];
  currentUser: string;
  actions: {
    sendMessage: (payload: { text: string; timestamp: string }) => void;
  };
}

function useComponent(props: Props) {
  const [text, setText] = useState('');
  const messageListRef = useRef<HTMLDivElement>(null);

  const handleSend = useCallback(() => {
    if (!text.trim()) return;
    props.actions.sendMessage({
      text: text.trim(),
      timestamp: new Date().toISOString(),
    });
    setText('');
  }, [props.actions, text]);

  useEffect(() => {
    if (messageListRef.current) {
      messageListRef.current.scrollTop = messageListRef.current.scrollHeight;
    }
  }, [props.messages]);

  return { text, setText, handleSend, messageListRef };
}

export default function Component(props: Props) {
  const { text, setText, handleSend, messageListRef } = useComponent(props);

  return (
    <Card shadow="md" padding={0} style={{ height: '500px', display: 'flex', flexDirection: 'column' }}>
      <Box paddingX={16} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{props.title}</Heading>
          <Badge variant="primary">{props.messages.length} messages</Badge>
        </Stack>
      </Box>

      <div ref={messageListRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)' }}>
        <Stack gap={12}>
          {props.messages.map((m) => (
            <Box key={m.id} style={{ alignSelf: m.sender === props.currentUser ? 'end' : 'start', maxWidth: '80%' }}>
              <Card
                padding={12}
                shadow="none"
                style={{ background: m.sender === props.currentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}
              >
                <Text variant="bodySmall" color={m.sender === props.currentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'} style={{ fontWeight: 600 }}>{m.sender}</Text>
                <Text variant="body" color={m.sender === props.currentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>{m.text}</Text>
                <Text variant="caption" color={m.sender === props.currentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'} style={{ opacity: 0.7, marginTop: 4 }}>{new Date(m.timestamp).toLocaleTimeString()}</Text>
              </Card>
            </Box>
          ))}
        </Stack>
      </div>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" gap={8}>
          <Input label="Message" value={text} onChange={setText} placeholder="Type a message..." style={{ flex: 1 }} onKeyDown={(e: any) => e.key === 'Enter' && handleSend()} />
          <Button variant="primary" onClick={handleSend} disabled={!text.trim()}>Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Stock {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
}

interface Props {
