import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: unknown;
}

// Action handlers (call these from event handlers):
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}
function useComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    avatar: '🧑‍💻',
    role: 'Developer',
    emailNotifications: true,
    theme: 'light'
  });

  const isStep1Valid = useMemo(() => formData.name.trim() !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email), [formData.name, formData.email]);

  const updateField = (field: string, value: any) => setFormData(prev => ({ ...prev, [field]: value }));

  const next = useCallback(() => setStep(s => Math.min(s + 1, 3)), []);
  const back = useCallback(() => setStep(s => Math.max(s - 1, 1)), []);

  const complete = useCallback(() => {
    // @ts-ignore
    props.actions.complete(formData);
  }, [formData, props]);

  return { step, formData, updateField, next, back, complete, isStep1Valid };
}

export default function Component(props: Props) {
  const { step, formData, updateField, next, back, complete, isStep1Valid } = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Onboarding - Step {step} of 3</Heading>
        <Progress value={(step - 1) * 50} max={100} />

        <Card padding={24}>
          {step === 1 && (
            <Stack gap={16}>
              <Heading level={4}>Profile Setup</Heading>
              <Input label="Name" value={formData.name} onChange={(v) => updateField('name', v)} required />
              <Input label="Email" value={formData.email} onChange={(v) => updateField('email', v)} required type="email" />
              <Text variant="label">Avatar</Text>
              <Row gap={8}>
                {['🧑‍💻', '👩‍🎨', '👨‍💼', '🤖'].map(emoji => (
                  <Button key={emoji} variant={formData.avatar === emoji ? 'primary' : 'secondary'} onClick={() => updateField('avatar', emoji)}>{emoji}</Button>
                ))}
              </Row>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Heading level={4}>Preferences</Heading>
              <Select label="Role" value={formData.role} onChange={(v) => updateField('role', v)} options={[{value:'Developer', label:'Developer'}, {value:'Designer', label:'Designer'}, {value:'Manager', label:'Manager'}, {value:'Other', label:'Other'}]} />
              <Toggle label="Email notifications" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
              <Toggle label="Dark mode" checked={formData.theme === 'dark'} onChange={(v) => updateField('theme', v ? 'dark' : 'light')} />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={16}>
              <Heading level={4}>Review & Confirm</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Role: {formData.role}</Text>
              <Text>Theme: {formData.theme}</Text>
            </Stack>
          )}
        </Card>

        <Row gap={16} justify="between">
          <Button variant="ghost" onClick={back} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button onClick={next} disabled={step === 1 && !isStep1Valid}>Next</Button>
          ) : (
            <Button variant="primary" onClick={complete}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
